(function(g){'use strict';class P{constructor(){this.v={};this.ready=true;this.init()}init(){console.log('PYTML: Ready!');this.processPage()}evaluatePython(c,i={}){try{const v={...this.v,...i};let d='';for(const[k,val]of Object.entries(v)){if(typeof val==='string'){d+=`let ${k}="${val}";\n`}else if(typeof val==='number'){d+=`let ${k}=${val};\n`}else{d+=`let ${k}=${JSON.stringify(val)};\n`}}let o='';const l=console.log;console.log=(...a)=>{o+=a.join(' ')+'\n';l(...a)};let js=[];const lines=c.split('\n');for(let line of lines){line=line.trim();if(!line)continue;if(line.startsWith('print(')&&line.endsWith(')')){let content=line.slice(6,-1);js.push(`console.log(${content});`)}else if(line.includes('=')&&!line.includes('if')&&!line.includes('for')&&!line.includes('while')){js.push(line+';')}else if(line.startsWith('if ')){let condition=line.slice(3);js.push(`if(${condition}){`)}else if(line==='else:'){js.push(`}else{`)}else if(line.startsWith('for ')){let m=line.match(/for (\w+) in (.+):/);if(m){let varName=m[1];let iterable=m[2];js.push(`for(let ${varName} of ${iterable}){`)}}else if(line.startsWith('while ')){let condition=line.slice(6,-1);js.push(`while(${condition}){`)}else if(line==='end'){js.push(`}`)}else{js.push(line)}}const e=new Function(d+js.join('\n'));e();console.log=l;return o}catch(e){return`Error: ${e.message}`}}async run(c,i={}){return this.evaluatePython(c,i)}collectInputs(e){const i={};const f=e.closest('[data-python-form]');if(f){const a=f.querySelectorAll('input, select, textarea');for(const el of a){if(el.name){let v=el.value;if(el.type==='number'){v=parseFloat(v)}else if(el.type==='checkbox'){v=el.checked}i[el.name]=v}}}return i}async processPage(){const t=document.querySelectorAll('[data-python-text]');for(const e of t){const c=e.getAttribute('data-python-text');const r=this.evaluatePython(`print(${c})`);e.textContent=r.trim()}const h=document.querySelectorAll('[data-python-html]');for(const e of h){const c=e.getAttribute('data-python-html');const r=this.evaluatePython(`print(${c})`);e.innerHTML=r.trim()}const b=document.querySelectorAll('[data-python]');for(const btn of b){const c=btn.getAttribute('data-python');const t=btn.getAttribute('data-target');btn.addEventListener('click',async()=>{const i=this.collectInputs(btn);const r=this.evaluatePython(c,i);if(t){const te=document.querySelector(t);if(te){te.textContent=r}}})}}}const p=new P;g.pytml=p})(window);
